template<const int N>
class Matrix {
public:
	// 下标从 1 开始
	array<array<ll, N + 1>, N + 1> mat;

	Matrix() {
		for (int i = 0; i <= N; i++)
			for (int j = 0; j <= N; j++)
				mat[i][j] = 0;
	}

	Matrix operator* (const Matrix& x) {
		// 矩阵乘法
		// 进行：行向量(答案矩阵) = 行向量(答案矩阵) * 矩阵(系数矩阵) 
		Matrix ret;
		for (int i = 1; i <= N; i++)
			for (int k = 1; k <= N; k++) {
				if (mat[i][k] == 0) continue; // 简单剪枝
				for (int j = 1; j <= N; j++) {
					ret.mat[i][j] = (ret.mat[i][j] + mat[i][k] * x.mat[k][j] % mod) % mod;
				}
			}
		return ret;
	}

	void ksm(ll k, Matrix& base) {
		while (k) {
			if (k & 1)*this = *this * base;
			base = base * base;
			k >>= 1;
		}
	}

	void init_ans() {
		mat[1][1] = 1;
	}

	void init_base(int m) {
		// dp[i] = dp[i - 1] + dp[i - m]
		mat[1][1] = 1;
		mat[m][1] = 1;
		fa(i, 2, m)mat[i - 1][i] = 1; // 继承上一维 dp 用
	}
};

Matrix<105> ans, base;
void solve(int CASE)
{
	ll n, m; cin >> n >> m;
	ans.init_ans();
	base.init_base(m);
	ans.ksm(n, base);
	cout << ans.mat[1][1] << endl;
	return;
}
